   493→  <script>
   494→    // Typing Animation - Sequential typing for multiple role lines
   495→    const roles = ['Data Scientist', 'Full Stack Developer', 'ML Engineer'];
   496→
   497→    function typeRole(lineIndex, text, cb) {
   498→      const lines = document.querySelectorAll('.role-line');
   499→      const textSpan = lines[lineIndex].querySelector('.role-text');
   500→      const cursor = lines[lineIndex].querySelector('.cursor');
   501→      cursor.classList.remove('hidden');
   502→      let i = 0;
   503→      const timer = setInterval(() => {
   504→        textSpan.textContent += text[i++];
   505→        if (i === text.length) {
   506→          clearInterval(timer);
   507→          if (cb) {
   508→            cb();
   509→            cursor.classList.add('hidden');
   510→          }
   511→        }
   512→      }, 60);
   513→    }
   514→
   515→    // Start typing animation on page load
   516→    typeRole(0, roles[0], () =>
   517→      setTimeout(() => typeRole(1, roles[1], () =>
   518→        setTimeout(() => typeRole(2, roles[2], null), 200)
   519→      ), 200)
   520→    );
   521→
   522→    // Navbar Active Link
   523→    const navLinks = document.querySelectorAll('.nav-link');
   524→
   525→    navLinks.forEach(link => {
   526→      link.addEventListener('click', (e) => {
   527→        navLinks.forEach(l => l.classList.remove('active'));
   528→        link.classList.add('active');
   529→      });
   530→    });
   531→
   532→    // Update active link on scroll
   533→    window.addEventListener('scroll', () => {
   534→      let current = '';
   535→      const sections = document.querySelectorAll('section[id]');
   536→
   537→      sections.forEach(section => {
   538→        const sectionTop = section.offsetTop;
   539→        const sectionHeight = section.clientHeight;
   540→        if (scrollY >= sectionTop - 200) {
   541→          current = section.getAttribute('id');
   542→        }
   543→      });
   544→
   545→      navLinks.forEach(link => {
   546→        link.classList.remove('active');
   547→        if (link.getAttribute('data-section') === current) {
   548→          link.classList.add('active');
   549→        }
   550→      });
   551→    });
